1	import type { Request, Response, NextFunction } from "express";
2	import type { AuthUser, RoleType, AuthResult } from "./types.js";
3	import { findById } from "../db.js";
4	
5	// ── Session helpers ──
6	
7	export function getCurrentUser(req: Request): AuthUser | null {
8	  const userId = req.session?.userId;
9	  if (!userId) return null;
10	  const row = findById<{ display_name: string; roles: string }>("users", userId);
11	  if (!row) return null;
12	  return {
13	    userId,
14	    displayName: row.display_name,
15	    roles: parseRoles(row.roles),
16	  };
17	}
18	
19	function parseRoles(raw: string | string[]): RoleType[] {
20	  if (Array.isArray(raw)) return raw.filter(r => ["rider","judge","organizer","admin"].includes(r)) as RoleType[];
21	  try { return JSON.parse(raw); } catch { return []; }
22	}
23	
24	export function requireLogin(req: Request, res: Response, next: NextFunction): void {
25	  if (!req.session?.userId) { res.status(401).json({ error: "Login required" }); return; }
26	  next();
27	}
