29	export interface ResourceContext {
30	  ownerUserId?: string;
31	  assignedJudgeUserId?: string;
32	  raceOrganizerIds?: string[];
33	  visibility?: string;
34	  isPublished?: boolean;
35	}
36	
37	export function authorize(user: AuthUser | null, resourceType: string, action: string, ctx: ResourceContext = {}): AuthResult {
38	  if (user?.roles.includes("admin")) return { allowed: true };
39	
40	  const scope = getRequiredScope(resourceType, action);
41	
42	  if (scope === "PUBLIC") {
43	    if (ctx.visibility === "public" && ctx.isPublished !== false) return { allowed: true };
44	    return { allowed: false, reason: "Resource is not publicly visible" };
45	  }
46	
47	  if (!user) return { allowed: false, reason: "Login required" };
48	
49	  if (scope === "OWN") {
50	    if (ctx.ownerUserId === user.userId) return { allowed: true };
51	    return { allowed: false, reason: "Not the owner" };
52	  }
53	
54	  if (scope === "ASSIGNED") {
55	    if (ctx.assignedJudgeUserId === user.userId) return { allowed: true };
56	    return { allowed: false, reason: "Not assigned" };
57	  }
58	
59	  if (scope === "MANAGED_RACE") {
60	    if (!user.roles.includes("organizer")) return { allowed: false, reason: "Not an organizer" };
61	    if (ctx.raceOrganizerIds?.includes(user.userId) || !ctx.raceOrganizerIds) return { allowed: true };
62	    return { allowed: false, reason: "Not an organizer of this race" };
63	  }
64	
65	  return { allowed: false, reason: "Insufficient permissions" };
66	}
