68	// ── Permission matrix ──
69	type ScopeReq = "PUBLIC" | "OWN" | "ASSIGNED" | "MANAGED_RACE" | "SYSTEM";
70	const MATRIX: Record<string, Record<string, ScopeReq>> = {
71	  Race: { view_public:"PUBLIC", view_private:"MANAGED_RACE", create:"MANAGED_RACE", edit:"MANAGED_RACE", publish:"MANAGED_RACE", archive:"MANAGED_RACE" },
72	  Registration: { submit:"OWN", view:"OWN", approve:"MANAGED_RACE", reject:"MANAGED_RACE", withdraw:"OWN" },
73	  RaceProject: { view_status:"OWN", register_ca_connection:"OWN", manage_ca_connection:"OWN", view_session_summary:"OWN", view_raw_session:"MANAGED_RACE" },
74	  Work: { view_public:"PUBLIC", view_private:"OWN", create:"OWN", submit:"OWN", lock:"MANAGED_RACE", publish:"MANAGED_RACE", hide:"OWN", review:"ASSIGNED" },
75	  Evidence: { view_public:"PUBLIC", view_private_summary:"OWN", set_visibility:"OWN", cite_in_report:"MANAGED_RACE" },
76	  JudgeAssignment: { view:"ASSIGNED", create:"MANAGED_RACE", update:"MANAGED_RACE", remove:"MANAGED_RACE" },
77	  JudgingRecord: { view_published_summary:"PUBLIC", view_private:"OWN", create:"ASSIGNED", submit:"ASSIGNED", update_before_submit:"ASSIGNED" },
78	  Award: { view_published:"PUBLIC", view_draft:"MANAGED_RACE", create_draft:"MANAGED_RACE", edit_draft:"MANAGED_RACE", publish:"MANAGED_RACE", withdraw_publication:"MANAGED_RACE" },
79	  Projection: { view_public:"PUBLIC", view_internal:"MANAGED_RACE", rebuild:"MANAGED_RACE", inspect_status:"MANAGED_RACE" },
80	  Report: { view_public_published:"PUBLIC", view_private:"OWN", generate:"MANAGED_RACE", edit:"MANAGED_RACE", publish:"MANAGED_RACE", regenerate:"MANAGED_RACE" },
81	  User: { sign_in_github:"PUBLIC", update_profile:"OWN", view_public_profile:"PUBLIC", view_private_profile:"OWN", update_roles:"SYSTEM" },
82	  Announcement: { view_public:"PUBLIC", view_private:"MANAGED_RACE", create:"MANAGED_RACE", edit:"MANAGED_RACE", publish:"MANAGED_RACE", hide:"MANAGED_RACE" },
83	  ScreenDisplay: { view_public_display:"PUBLIC", configure:"MANAGED_RACE", switch_mode:"MANAGED_RACE", fallback:"MANAGED_RACE" },
84	};
85	
86	function getRequiredScope(resourceType: string, action: string): ScopeReq {
87	  return MATRIX[resourceType]?.[action] ?? "SYSTEM";
88	}
