1	import type { Express, Request, Response } from "express";
2	import { Router } from "express";
3	import { v4 as uuid } from "uuid";
4	import { findAll, findById, findBy, insert, update } from "../../db.js";
5	import { getCurrentUser, requireLogin, authorize } from "../../shared/auth.js";
6	import type { RoleType, User } from "../../shared/types.js";
