10	export function registerIdentityRoutes(app: Express): void {
11	  const auth = Router();
12	  const admin = Router();
13	
14	  // ── GitHub OAuth (simplified for dev) ──
15	  auth.post("/github", (req: Request, res: Response) => {
16	    const { githubAccount, displayName } = req.body;
17	
18	    if (!githubAccount || typeof githubAccount !== "string") {
19	      res.status(400).json({ error: "githubAccount is required" });
20	      return;
21	    }
22	
23	    // Find existing user or create
24	    let user = findBy<User>("users", "githubAccount", githubAccount);
25	
26	    if (!user) {
27	      user = {
28	        id: uuid(),
29	        githubAccount,
30	        displayName: displayName || githubAccount,
31	        profileCompleted: !!displayName,
32	        roles: [],
33	        createdAt: new Date().toISOString(),
34	        updatedAt: new Date().toISOString(),
35	      } as User;
36	      insert("users", user);
37	    }
38	
39	    // Set session
40	    req.session.userId = user.id;
41	    req.session.save((err) => {
42	      if (err) {
43	        res.status(500).json({ error: "Session save failed" });
44	        return;
45	      }
46	      res.json(toUserResponse(user));
47	    });
48	  });
49	
50	  // ── Current user ──
51	  auth.get("/me", requireLogin, (req: Request, res: Response) => {
52	    const user = getCurrentUser(req);
53	    if (!user) { res.status(401).json({ error: "Not authenticated" }); return; }
54	
55	    const row = findById<User>("users", user.userId);
56	    if (!row) { res.status(404).json({ error: "User not found" }); return; }
57	
58	    res.json(toUserResponse(row));
59	  });
60	
61	  // ── Update profile ──
62	  auth.patch("/me", requireLogin, (req: Request, res: Response) => {
63	    const user = getCurrentUser(req);
64	    if (!user) { res.status(401).json({ error: "Not authenticated" }); return; }
65	
66	    const result = authorize(user, "User", "update_profile", { ownerUserId: user.userId });
67	    if (!result.allowed) { res.status(403).json({ error: result.reason }); return; }
68	
69	    const { displayName } = req.body;
70	    if (!displayName || typeof displayName !== "string") {
71	      res.status(400).json({ error: "displayName is required" });
72	      return;
73	    }
74	
75	    const updated = update<User>("users", user.userId, {
76	      displayName,
77	      profileCompleted: true,
78	      updatedAt: new Date().toISOString(),
79	    });
80	    if (!updated) { res.status(404).json({ error: "User not found" }); return; }
81	
82	    res.json({ ok: true, displayName });
83	  });
84	
85	  // ── Logout ──
86	  auth.post("/logout", (req: Request, res: Response) => {
87	    req.session.destroy((err) => {
88	      if (err) { res.status(500).json({ error: "Logout failed" }); return; }
89	      res.clearCookie("connect.sid");
90	      res.json({ ok: true });
91	    });
92	  });
93	
94	  // ── Admin: List users ──
95	  admin.get("/users", requireLogin, (req: Request, res: Response) => {
96	    const user = getCurrentUser(req);
97	    if (!user) { res.status(401).json({ error: "Not authenticated" }); return; }
98	
99	    const result = authorize(user, "User", "update_roles", {});
100	    if (!result.allowed) { res.status(403).json({ error: result.reason }); return; }
101	
102	    const rows = findAll<User>("users");
103	    res.json(rows.map(toUserResponse));
104	  });
105	
106	  // ── Admin: Update user roles ──
107	  admin.put("/users/:id/roles", requireLogin, (req: Request, res: Response) => {
108	    const adminUser = getCurrentUser(req);
109	    if (!adminUser) { res.status(401).json({ error: "Not authenticated" }); return; }
110	
111	    const result = authorize(adminUser, "User", "update_roles", {});
112	    if (!result.allowed) { res.status(403).json({ error: result.reason }); return; }
113	
114	    const { roles } = req.body;
115	    if (!Array.isArray(roles)) { res.status(400).json({ error: "roles must be an array" }); return; }
116	    for (const r of roles) {
117	      if (!VALID_ROLES.includes(r)) { res.status(400).json({ error: `Invalid role: ${r}` }); return; }
118	    }
119	
120	    const target = findById<User>("users", req.params.id);
121	    if (!target) { res.status(404).json({ error: "User not found" }); return; }
122	
123	    update<User>("users", req.params.id, {
124	      roles: roles as any,
125	      updatedAt: new Date().toISOString(),
126	    });
127	
128	    res.json({ ok: true, userId: req.params.id, roles });
129	  });
130	
131	  app.use("/auth", auth);
132	  app.use("/admin", admin);
133	  console.log("[identity] Routes registered: /auth/*, /admin/*");
134	}
135	
136	function toUserResponse(u: User) {
137	  return {
138	    userId: u.id,
139	    githubAccount: u.githubAccount,
140	    displayName: u.displayName,
141	    profileCompleted: u.profileCompleted,
142	    roles: u.roles,
143	  };
144	}
