17	export function registerCommunicationRoutes(app: Express): void {
18	  const router = Router();
19	
20	  // ── Public: List published announcements ──
21	  router.get("/announcements", (_req: Request, res: Response) => {
22	    const all = findAll<Announcement>("announcements");
23	    const published = all
24	      .filter(a => a.visibility === "public" && a.published_at)
25	      .sort((a, b) => (b.published_at || "").localeCompare(a.published_at || ""));
26	    res.json(published);
27	  });
28	
29	  // ── Organizer: Create ──
30	  router.post("/announcements", requireLogin, (req: Request, res: Response) => {
31	    const user = getCurrentUser(req);
32	    const result = authorize(user!, "Announcement", "create", {});
33	    if (!result.allowed) { res.status(403).json({ error: result.reason }); return; }
34	
35	    const { raceId, title, body } = req.body;
36	    if (!raceId || !title || !body) {
37	      res.status(400).json({ error: "raceId, title, and body are required" }); return;
38	    }
39	
40	    const announcement: Announcement = {
41	      id: uuid(),
42	      race_id: raceId,
43	      title,
44	      body,
45	      visibility: "private",
46	      published_at: null,
47	      created_at: new Date().toISOString(),
48	    };
49	    insert("announcements", announcement);
50	    res.status(201).json(announcement);
51	  });
52	
53	  // ── Organizer: Edit ──
54	  router.patch("/announcements/:id", requireLogin, (req: Request, res: Response) => {
55	    const user = getCurrentUser(req);
56	    const result = authorize(user!, "Announcement", "edit", {});
57	    if (!result.allowed) { res.status(403).json({ error: result.reason }); return; }
58	
59	    const { title, body } = req.body;
60	    const updated = update<Announcement>("announcements", req.params.id, {
61	      ...(title ? { title } : {}),
62	      ...(body ? { body } : {}),
63	    } as any);
64	    if (!updated) { res.status(404).json({ error: "Not found" }); return; }
65	    res.json(updated);
66	  });
67	
68	  // ── Organizer: Publish ──
69	  router.post("/announcements/:id/publish", requireLogin, (req: Request, res: Response) => {
70	    const user = getCurrentUser(req);
71	    const result = authorize(user!, "Announcement", "publish", {});
72	    if (!result.allowed) { res.status(403).json({ error: result.reason }); return; }
73	
74	    const updated = update<Announcement>("announcements", req.params.id, {
75	      visibility: "public",
76	      published_at: new Date().toISOString(),
77	    } as any);
78	    if (!updated) { res.status(404).json({ error: "Not found" }); return; }
79	    res.json(updated);
80	  });
81	
82	  // ── Organizer: Hide ──
83	  router.delete("/announcements/:id", requireLogin, (req: Request, res: Response) => {
84	    const user = getCurrentUser(req);
85	    const result = authorize(user!, "Announcement", "hide", {});
86	    if (!result.allowed) { res.status(403).json({ error: result.reason }); return; }
87	
88	    update<Announcement>("announcements", req.params.id, {
89	      visibility: "private",
90	      published_at: null,
91	    } as any);
92	    res.json({ ok: true });
93	  });
94	
95	  // ── Public: Rider profile ──
96	  router.get("/riders/:slug", (req: Request, res: Response) => {
97	    const rider = findById("users", req.params.slug);
98	    if (!rider) { res.status(404).json({ error: "Rider not found" }); return; }
99	
100	    // Cross-module aggregations — available once dependent tables exist
101	    const registrations = filterBy("registrations", "user_id", req.params.slug);
102	    const works = filterBy("works", "registration_id", "__any__"); // placeholder
103	
104	    res.json({
105	      userId: (rider as any).id,
106	      displayName: (rider as any).displayName,
107	      registrations: registrations.length,
108	      roles: (rider as any).roles || [],
109	    });
110	  });
111	
112	  app.use("/communication", router);
113	  console.log("[communication] Routes registered: /communication/*");
114	}
